"use strict";(globalThis.webpackChunkdocusaurus_site=globalThis.webpackChunkdocusaurus_site||[]).push([[830],{4988(e){e.exports=JSON.parse('{"slug":"m16","title":"M16 in backyard (Untracked)","date":"2025-09","year":null,"featuredRank":2,"thumb":"/img/gallery/_gen/m16-thumb.jpg","image":"/img/gallery/_gen/m16-full.jpg","aspect":0.9670424978317432,"srcAbs":"/mnt/ssd/eason_project/website_raw/gallery/img/m16.jpg","source":"@site/gallery/m16.mdx","sourceFilePath":"gallery/m16.mdx","_content":"\\nFirst time trying M16 Eagle Nebula, untracked. Stock EOS R8, RF 70-200 f4 L IS USM @ 200mm f5.6, 500x 1.6s ISO 3200. Processed in PixInsight.\\n\\nEyeballed the focus... will get a tracker and bahtinov mask soon. PixInsight brought out so much detail compared to Siril, and NoiseX was a life saver, but the Pillars of Creation remains very noisy and there are artifacts after BlueX. Taken in Bortle 8."}')}}]);